/etc/nginx/nginx.conf:    map $args $cleaned_args {
/etc/nginx/nginx.conf-        default          $args;
/etc/nginx/nginx.conf-        ""               "";
--
/etc/nginx/nginx.conf:    map "$rocket_is_logged_in:$request_method:$cleaned_args" $rocket_skip_reason {
/etc/nginx/nginx.conf-        default "";
/etc/nginx/nginx.conf-        "~^1:" "logged_in";
--
/etc/nginx/nginx.conf:    map $rocket_skip_reason $rocket_cache_file {
/etc/nginx/nginx.conf-        default "/wp-content/cache/wp-rocket/$http_host/$uri/index-https.html";
/etc/nginx/nginx.conf-        "~.+" "";
--
/etc/nginx/nginx.conf:    map "$rocket_skip_reason:$uri" $rocket_root_cache {
/etc/nginx/nginx.conf-        default "";
/etc/nginx/nginx.conf-        ":/" "/wp-content/cache/wp-rocket/$http_host/index-https.html";

=== FPM pool config ===
