echo "=== ALB amazonia-alb está associado a alguma WebACL? ==="
ALB_ARN=$(aws --profile Concertação elbv2 describe-load-balancers --names amazonia-alb --region sa-east-1 --query 'LoadBalancers[0].LoadBalancerArn' --output text)
aws --profile Concertação wafv2 get-web-acl-for-resource --resource-arn "$ALB_ARN" --region sa-east-1 2>&1 | python3 -c "
import sys,json
try:
    d=json.load(sys.stdin)
    wa = d.get('WebACL')
    if wa: print(f\"Associado a: {wa['Name']} ({wa['ARN']})\")
    else: print('Sem WebACL associada')
except Exception as e: print('ERROR:', e, file=sys.stderr)
" 2>&1

