1	#!/usr/bin/env bash
2	# ==============================================================================
3	# Nginx Site Configuration Script - Single Environment with Cache Control
4	# Autor: Daniel Cambría + Warp
5	# Versao: 1.8.0
6	#
7	# Configura site Nginx com suporte completo a SSL via Load Balancer
8	# para o ambiente especificado em ENVIRONMENT (prod|hml|dev)
9	# Usa configurações de cache definidas no ../.env
10	#
11	# v1.1.0: Rate limiting, timeouts diferenciados por location, HSTS condicional,
12	#         bloqueio wp-cron HTTP externo, xmlrpc rate limit (não deny — WPML usa)
13	# v1.2.0: Criar bloco listen 8080 para ALB health check (/health, /health.txt)
14	# v1.3.0: Content-Security-Policy em security-headers.conf (Elementor-compatible)
15	# v1.4.0: Fix MULTISITE via get_env_variable (era ${MULTISITE:-false}, ignorava _PROD/_HML)
16	# v1.5.0: CSP v3 — GTM, GA, Google Ads, Meta Pixel, RD Station, VLibras, CDN fonts
17	# v1.6.0: WP Rocket nginx bypass — serve HTML cacheado sem PHP (~0.015s vs ~1-5s)
18	# v1.7.0: cleaned_args map (strip tracking QS + TEC crawler traps), CF crawler rate limit
19	# v1.8.0: robots.txt (prod), TEC day-view redirect (multisite), TEC REST API rate limit+timeout
20	# ==============================================================================
21	set -euo pipefail
22	
23	readonly WP_SCRIPT_DESC="Configura sites Nginx"
24	
25	# Parse argumentos para detectar --help
26	for arg in "$@"; do
27	    if [[ "$arg" == "--help" ]] || [[ "$arg" == "-h" ]]; then
28	        cat <<EOF
29	================================================================================
30	Script: 03-nginx-sites.sh
31	Descrição: Configura sites Nginx
32	================================================================================
33	
34	USO:
35	  $0
36	
37	COMPORTAMENTO:
38	  Configura Nginx para servir WordPress com SSL via Load Balancer:
39	  - Cria snippets de configuração (security headers, PHP-FPM)
40	  - Detecta versão PHP instalada e configura socket apropriado
41	  - Configura nginx.conf para SSL via X-Forwarded-Proto
42	  - Configura Real IP para capturar IP do cliente via Load Balancer
43	  - Cria configuração de site específica por ambiente (prod/hml/dev)
44	  - Aplica configurações de cache personalizadas por ambiente
45	  - Configura drop server (bloqueia acesso direto por IP - segurança)
46	  - Cria health check endpoint na porta 8080 para Load Balancer
47	  - Ativa site e recarrega Nginx
48	
49	VARIÁVEIS DE AMBIENTE (.env):
50	  ENVIRONMENT                 Ambiente ativo (prod|hml|dev)
51	  FQDN_{ENV}                 FQDN do site (ex: FQDN_PROD)
52	  WP_ROOT_{ENV}              Diretório raiz do WordPress
53	  CACHE_CONTROL_{ENV}        Diretivas Cache-Control para arquivos estáticos
54	  CACHE_EXPIRES_{ENV}        Tempo de expiração do cache
55	  ROBOTS_TAG_{ENV}           Tag robots para ambientes não-prod
56	  VPC_CIDR_TRUSTED           CIDR da VPC para Real IP (padrão: 10.0.0.0/8)
57	
58	NOTAS:
59	  - SSL terminado no Load Balancer, não no servidor
60	  - Acesso direto por IP bloqueado (return 444)
61	  - Health check na porta 8080 gerenciado por arquivo dedicado (não por este script)
62	  - Configurações de cache controladas por ambiente
63	
64	================================================================================
65	EOF
66	        exit 0
67	    fi
68	done
69	
70	# Carregar helpers usando a abordagem padronizada
71	source "$(dirname "$0")/../helpers/load-helpers.sh"
72	load_helper "common.sh"
73	load_helper "config-helper.sh"
74	
75	log_info "Configurando site Nginx para ambiente: ${ENVIRONMENT}"
76	
77	# ==============================================================================
78	# SNIPPETS COMUNS
79	# ==============================================================================
80	
81	log_info "Criando snippets de configuração..."
82	
83	# Security headers
84	cat > /etc/nginx/snippets/security-headers.conf << 'SECEOF'
85	add_header X-Frame-Options "SAMEORIGIN" always;
86	add_header X-Content-Type-Options "nosniff" always;
87	add_header Referrer-Policy "strict-origin-when-cross-origin" always;
88	add_header Permissions-Policy "interest-cohort=()" always;
89	# CSP: unsafe-inline/eval necessários para Elementor + JetEngine + WPML
90	# data: em script-src necessário para WP Rocket Delay JS (execução via data: URIs)
91	# Domínios: GTM, GA, Google Ads, Meta Pixel, RD Station, VLibras, reCAPTCHA, Google Charts
92	# frame-ancestors substitui X-Frame-Options em browsers modernos
93	add_header Content-Security-Policy "default-src 'self'; script-src 'self' 'unsafe-inline' 'unsafe-eval' https://www.googletagmanager.com https://www.google-analytics.com https://www.google.com https://www.gstatic.com https://googleads.g.doubleclick.net https://connect.facebook.net https://d335luupugsy2.cloudfront.net https://d1sag09wwfbul8.cloudfront.net https://vlibras.gov.br https://cdn.jsdelivr.net blob: data:; style-src 'self' 'unsafe-inline' https://fonts.googleapis.com https://fonts.cdnfonts.com; img-src 'self' data: https:; font-src 'self' data: https://fonts.gstatic.com https://fonts.cdnfonts.com; frame-src 'self' https://www.google.com https://vlibras.gov.br https://www.facebook.com; frame-ancestors 'self'; connect-src 'self' https://www.google-analytics.com https://analytics.google.com https://www.googletagmanager.com https://stats.g.doubleclick.net https://www.google.com https://connect.facebook.net https://vlibras.gov.br https://popups.rdstation.com.br https://d335luupugsy2.cloudfront.net; worker-src 'self' blob:; media-src 'self' https://s3.us-east-1.amazonaws.com; object-src 'none';" always;
94	SECEOF
95	
96	# PHP-FPM configuration - detecta versão PHP automaticamente
97	log_info "Detectando versão PHP instalada..."
98	
99	# Detectar versão PHP instalada
100	if [[ -S "/run/php/php8.3-fpm-wordpress.sock" ]]; then
101	    PHP_SOCKET="/run/php/php8.3-fpm-wordpress.sock"
102	    log_success "Usando socket PHP 8.3 customizado"
103	elif [[ -S "/run/php/php8.2-fpm-wordpress.sock" ]]; then
104	    PHP_SOCKET="/run/php/php8.2-fpm-wordpress.sock"
105	    log_success "Usando socket PHP 8.2 customizado"
106	elif [[ -S "/run/php/php8.1-fpm-wordpress.sock" ]]; then
107	    PHP_SOCKET="/run/php/php8.1-fpm-wordpress.sock"
108	    log_success "Usando socket PHP 8.1 customizado"
109	elif [[ -S "/run/php/php8.3-fpm.sock" ]]; then
110	    PHP_SOCKET="/run/php/php8.3-fpm.sock"
111	    log_success "Usando socket PHP 8.3 padrão"
112	elif [[ -S "/run/php/php8.2-fpm.sock" ]]; then
113	    PHP_SOCKET="/run/php/php8.2-fpm.sock"
114	    log_success "Usando socket PHP 8.2 padrão"
115	elif [[ -S "/run/php/php8.1-fpm.sock" ]]; then
116	    PHP_SOCKET="/run/php/php8.1-fpm.sock"
117	    log_success "Usando socket PHP 8.1 padrão"
118	else
119	    log_error "Nenhum socket PHP-FPM encontrado!"
120	    log_info "Sockets disponíveis em /run/php/:"
121	    ls -la /run/php/ || echo "Diretório /run/php/ não encontrado"
122	    exit 1
123	fi
124	
125	log_info "Socket PHP selecionado: $PHP_SOCKET"
126	
127	cat > /etc/nginx/snippets/php-fpm.conf << PHPEOF
128	include fastcgi_params;
129	fastcgi_pass unix:$PHP_SOCKET;
130	fastcgi_param SCRIPT_FILENAME \$realpath_root\$fastcgi_script_name;
131	fastcgi_param HTTPS on;
132	fastcgi_connect_timeout 10;
133	PHPEOF
134	# Nota: fastcgi_read_timeout e fastcgi_send_timeout são definidos por location
135	# no server block (60s geral, 120s wp-admin, 300s async-upload) — não aqui.
136	
137	# ==============================================================================
138	# CONFIGURAÇÃO NGINX PRINCIPAL - SSL E REAL IP
139	# ==============================================================================
140	
141	log_info "Configurando nginx.conf para SSL e Real IP..."
142	
143	# Backup do nginx.conf original
144	cp /etc/nginx/nginx.conf /etc/nginx/nginx.conf.bak 2>/dev/null || true
145	
146	log_info "Verificando configurações de SSL e Real IP no nginx.conf..."
147	
148	# Configurar Real IP (para que nginx veja o IP real do visitante via X-Forwarded-For do ALB)
149	# Nota: o map $http_x_forwarded_proto → $fastcgi_https foi removido — fastcgi_param HTTPS on
150	# é definido estaticamente no snippet php-fpm.conf (EC2 sempre atrás de ALB com SSL offloading)
151	if ! grep -q "real_ip_header X-Forwarded-For" /etc/nginx/nginx.conf; then
152	    log_info "Configuração de Real IP não encontrada. Adicionando..."
153	
154	    # Usar VPC_CIDR_TRUSTED do .env (fallback: 10.0.0.0/8 cobre a maioria das VPCs AWS)
155	    VPC_CIDR="${VPC_CIDR_TRUSTED:-10.0.0.0/8}"
156	
157	    # Criar arquivo temporário com as configurações
158	    cat > /tmp/nginx_realip_config.tmp << RIPEOF
159	
160	    # ==== Real IP Configuration (ALB → EC2) ====
161	    real_ip_header X-Forwarded-For;
162	    real_ip_recursive on;
163	    set_real_ip_from ${VPC_CIDR};
164	RIPEOF
165	
166	    # Inserir as configurações após a linha 'http {'
167	    sed -i '/^http {$/r /tmp/nginx_realip_config.tmp' /etc/nginx/nginx.conf
168	
169	    # Remover arquivo temporário
170	    rm -f /tmp/nginx_realip_config.tmp
171	    log_success "Configuração de Real IP adicionada."
172	else
173	    log_info "Configuração de Real IP já existe. Nenhuma alteração necessária."
174	fi
175	
176	# Rate limiting zone: wp-login brute force (idempotente)
177	if ! grep -q "zone=wp_login" /etc/nginx/nginx.conf; then
178	    log_info "Adicionando rate limiting zone wp_login ao nginx.conf..."
179	    cat > /tmp/nginx_ratelimit.tmp << 'RLEOF'
180	
181	    # ==== Rate Limiting: wp-login brute force ====
182	    # $binary_remote_addr usa o IP real do cliente (ngx_http_realip_module já processou X-Forwarded-For)
183	    limit_req_zone $binary_remote_addr zone=wp_login:10m rate=5r/m;
184	
185	    # ==== Rate Limiting: CloudFront crawlers ====
186	    map $http_user_agent $is_cf_crawler {
187	        default             0;
188	        "Amazon CloudFront" 1;
189	        ""                  1;
190	    }
191	
192	    map $is_cf_crawler $cf_crawler_key {
193	        0   "";
194	        1   $binary_remote_addr;
195	    }
196	
197	    limit_req_zone $cf_crawler_key zone=cf_crawlers:10m rate=2r/s;
198	RLEOF
199	    sed -i '/^http {$/r /tmp/nginx_ratelimit.tmp' /etc/nginx/nginx.conf
200	    rm -f /tmp/nginx_ratelimit.tmp
201	    log_success "Rate limiting zones adicionadas."
202	else
203	    log_info "Rate limiting zones já existem. Nenhuma alteração necessária."
204	fi
205	
206	# ==============================================================================
207	# WP ROCKET NGINX BYPASS — serve HTML cacheado sem PHP
208	# ==============================================================================
209	
210	# Maps no bloco http {} para detectar cookies/method e resolver path do cache.
211	# WP Rocket grava HTML em wp-content/cache/wp-rocket/$host/$uri/index-https.html.
212	# Nginx serve direto do disco (~0.015s) se: não logado, GET, sem query string.
213	if ! grep -q "rocket_is_logged_in" /etc/nginx/nginx.conf; then
214	    log_info "Adicionando WP Rocket bypass maps ao nginx.conf..."
215	    cat > /tmp/nginx_rocket_maps.tmp << 'ROCKETEOF'
216	
217	    # ==== WP Rocket Nginx Bypass ====
218	    # Detecta cookies de login/postpass/comment para pular cache
219	    map $http_cookie $rocket_is_logged_in {
220	        default 0;
221	        "~*wordpress_logged_in_" 1;
222	        "~*wp-postpass_" 1;
223	        "~*comment_author_" 1;
224	    }
225	
226	    # Clean args: strip tracking QS e crawler traps do TEC (servir cache)
227	    # Se $args contém qualquer destes, mapeamos para "" (= sem QS = cache hit)
228	    map $args $cleaned_args {
229	        default          $args;
230	        ""               "";
231	        "~*gclid="       "";
232	        "~*gad_source="  "";
233	        "~*gbraid="      "";
234	        "~*gclsrc="      "";
235	        "~*utm_"         "";
236	        "~*fbclid="      "";
237	        "~*msclkid="     "";
238	        "~*_ga="         "";
239	        "~*_gl="         "";
240	        "~*ical="        "";
241	        "~*outlook-ical=" "";
242	        "~*nowprocket="  "";
243	        "~*eventDisplay=past" "";
244	        "~*tribe-bar-date=" "";
245	        "~*eventDate="   "";
246	    }
247	
248	    # Motivo para pular cache: logado, POST, ou query string funcional presente
249	    map "$rocket_is_logged_in:$request_method:$cleaned_args" $rocket_skip_reason {
250	        default "";
251	        "~^1:" "logged_in";
252	        "~^.:POST" "post_request";
253	        "~^.:GET:.+" "query_string";
254	    }
255	
256	    # Path do cache para URIs com trailing slash (maioria das páginas)
257	    map $rocket_skip_reason $rocket_cache_file {
258	        default "/wp-content/cache/wp-rocket/$http_host/$uri/index-https.html";
259	        "~.+" "";
260	    }
261	
262	    # Path do cache para a raiz (/) — sem trailing slash duplicada
263	    map "$rocket_skip_reason:$uri" $rocket_root_cache {
264	        default "";
265	        ":/" "/wp-content/cache/wp-rocket/$http_host/index-https.html";
266	    }
267	ROCKETEOF
268	    sed -i '/^http {$/r /tmp/nginx_rocket_maps.tmp' /etc/nginx/nginx.conf
269	    rm -f /tmp/nginx_rocket_maps.tmp
270	    log_success "WP Rocket bypass maps adicionados ao nginx.conf."
271	else
272	    log_info "WP Rocket bypass maps já existem no nginx.conf. Nenhuma alteração necessária."
273	fi
274	
275	# ==============================================================================
276	# CONFIGURAÇÃO DO SITE BASEADO NO AMBIENTE
277	# ==============================================================================
278	
279	# Validar ambiente
280	if [[ ! "${ENVIRONMENT}" =~ ^(prod|hml|dev)$ ]]; then
281	    log_error "ENVIRONMENT deve ser: prod, hml ou dev. Atual: ${ENVIRONMENT}"
282	    exit 1
283	fi
284	
285	log_info "Carregando configurações de cache para ambiente ${ENVIRONMENT}..."
286	
287	# Usar get_env_variable para resolver variáveis específicas do ambiente
288	FQDN=$(get_env_variable "FQDN" || echo "")
289	WP_ROOT=$(get_env_variable "WP_ROOT" || echo "")
290	CACHE_CONTROL=$(get_env_variable "CACHE_CONTROL" || echo "public, max-age=31536000, immutable")
291	CACHE_EXPIRES=$(get_env_variable "CACHE_EXPIRES" || echo "1y")
292	ROBOTS_TAG=$(get_env_variable "ROBOTS_TAG" || echo "")
293	
294	# Validar variáveis obrigatórias
295	if [[ -z "$FQDN" ]]; then
296	    log_error "FQDN não configurado para ambiente ${ENVIRONMENT}"
297	    log_error "Configure FQDN_${ENVIRONMENT^^} no arquivo ../.env"
298	    exit 1
299	fi
300	
301	if [[ -z "$WP_ROOT" ]]; then
302	    log_error "WP_ROOT não configurado para ambiente ${ENVIRONMENT}"
303	    log_error "Configure WP_ROOT_${ENVIRONMENT^^} no arquivo ../.env"
304	    exit 1
305	fi
306	
307	log_info "Configurações carregadas:"
308	log_info "  - Cache Expires: ${CACHE_EXPIRES}"
309	log_info "  - Cache Control: ${CACHE_CONTROL}"
310	log_info "  - Robots Tag: $([ -n "${ROBOTS_TAG}" ] && echo "Configurado" || echo "Desabilitado")"
311	
312	log_info "Configurando site para ambiente ${ENVIRONMENT}..."
313	
314	# HSTS: apenas em produção (evita HSTS permanente em ambientes não-prod que podem mudar de URL)
315	HSTS_HEADER=""
316	if [[ "${ENVIRONMENT}" == "prod" ]]; then
317	    HSTS_HEADER='add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;'
318	fi
319	
320	# Gerar bloco de rewrites para multisite subdirectory (se MULTISITE=true)
321	MULTISITE_REWRITES=""
322	STATIC_TRY_FILES="=404"
323	MULTISITE=$(get_env_variable "MULTISITE" || echo "false")
324	if [[ "${MULTISITE}" == "true" ]]; then
325	    log_info "Multisite ativado: adicionando rewrite rules de subdirectory ao nginx..."
326	    MULTISITE_REWRITES=$(cat << 'MSEOF'
327	
328	    # WordPress Multisite subdirectory rewrites
329	    if (!-e $request_filename) {
330	        rewrite /wp-admin$ $scheme://$host$uri/ permanent;
331	        rewrite ^(/[^/]+)?(/wp-.*) $2 last;
332	        rewrite ^(/[^/]+)?(/.*\.php) $2 last;
333	    }
334	MSEOF
335	)
336	    # Multisite: static files de subsites nao existem no filesystem, precisam do PHP
337	    STATIC_TRY_FILES="/index.php?\$args"
338	fi
339	
340	cat > "/etc/nginx/sites-available/${FQDN}" << SITEEOF
341	server {
342	    listen 80;
343	    server_name ${FQDN};
344	    root ${WP_ROOT};
345	    index index.php index.html;
346	    include /etc/nginx/snippets/security-headers.conf;
347	
348	    ${ROBOTS_TAG}
349	    ${HSTS_HEADER}
350	    client_max_body_size 128M;
351	
352	    # WordPress permalinks + WP Rocket bypass
353	    # Ordem: arquivo exato → cache raiz → cache página → diretório → PHP
354	    location / {
355	        limit_req zone=cf_crawlers burst=5 nodelay;
356	        try_files \$uri \$rocket_root_cache \$rocket_cache_file \$uri/ /index.php?\$args;
357	    }
358	${MULTISITE_REWRITES}
359	    # Static files caching - Configurações controladas por variáveis
360	    location ~* \.(?:js|css|png|jpg|jpeg|gif|svg|woff2?|ttf|eot)$ {
361	        expires ${CACHE_EXPIRES};
362	        add_header Cache-Control "${CACHE_CONTROL}";
363	        try_files \$uri ${STATIC_TRY_FILES};
364	    }
365	
366	    # Bloquear indexacao de PDFs pelo Google
367	    location ~* \.pdf$ {
368	        add_header X-Robots-Tag "noindex, nofollow" always;
369	        try_files \$uri =404;
370	    }
371	
372	    # TEC day-view: redirect crawlers para /eventos/ (colapsa superfície infinita de datas)
373	    # Multisite: (/[^/]+)? captura prefixo de subsite como /cultura/
374	    location ~ "^(/[^/]+)?/eventos/\\d{4}-\\d{2}-\\d{2}" {
375	        limit_req zone=cf_crawlers burst=2 nodelay;
376	        if (\$rocket_is_logged_in = 0) {
377	            return 301 \$1/eventos/;
378	        }
379	        try_files \$uri \$uri/ /index.php?\$args;
380	    }
381	
382	    # TEC REST API: rate limit + timeout curto (sem uso público)
383	    # Usa rewrite+break (não try_files) para que fastcgi_read_timeout 15 se aplique aqui
384	    location ~ ^/wp-json/tribe {
385	        limit_req zone=cf_crawlers burst=2 nodelay;
386	        rewrite ^ /index.php?\$args break;
387	        include /etc/nginx/snippets/php-fpm.conf;
388	        fastcgi_param HTTPS on;
389	        fastcgi_read_timeout 15;
390	        fastcgi_send_timeout 15;
391	    }
392	
393	    # Security restrictions
394	    location ~ /\.ht { deny all; }
395	    location ~* /(?:wp-config\.php|readme\.html|license\.txt)$ { deny all; }
396	
397	    # ==== Hardening: rate limiting e bloqueios ====
398	
399	    # wp-login.php: rate limit anti-brute-force (5 req/min, burst=3)
400	    location = /wp-login.php {
401	        limit_req zone=wp_login burst=3 nodelay;
402	        try_files \$uri =404;
403	        include /etc/nginx/snippets/php-fpm.conf;
404	        fastcgi_param HTTPS on;
405	        fastcgi_read_timeout 60;
406	        fastcgi_send_timeout 60;
407	    }
408	
409	    # xmlrpc.php: rate limit moderado — NÃO bloquear (WPML usa para sync multilíngue)
410	    # burst=5 permite sync de múltiplos posts sem throttling; impede abuso em massa
411	    location = /xmlrpc.php {
412	        limit_req zone=wp_login burst=5 nodelay;
413	        try_files \$uri =404;
414	        include /etc/nginx/snippets/php-fpm.conf;
415	        fastcgi_param HTTPS on;
416	        fastcgi_read_timeout 60;
417	        fastcgi_send_timeout 60;
418	    }
419	
420	    # wp-cron.php: bloquear acesso HTTP externo (cron roda via sistema PHP direto)
421	    # O rewrite multisite (flag last) garante que /subsite/wp-cron.php também é bloqueado
422	    location = /wp-cron.php {
423	        allow 127.0.0.1;
424	        deny all;
425	        try_files \$uri =404;
426	        include /etc/nginx/snippets/php-fpm.conf;
427	        fastcgi_param HTTPS on;
428	        fastcgi_read_timeout 60;
429	        fastcgi_send_timeout 60;
430	    }
431	
432	    # wp-admin/async-upload.php: upload de arquivos grandes (PDFs, imagens)
433	    location = /wp-admin/async-upload.php {
434	        try_files \$uri =404;
435	        include /etc/nginx/snippets/php-fpm.conf;
436	        fastcgi_param HTTPS on;
437	        fastcgi_read_timeout 300;
438	        fastcgi_send_timeout 300;
439	        client_max_body_size 128M;
440	    }
441	
442	    # wp-admin: operações longas (exports, imports, atualizações)
443	    location ~ ^/wp-admin/ {
444	        try_files \$uri \$uri/ /index.php?\$args;
445	        location ~ \.php$ {
446	            try_files \$uri =404;
447	            include /etc/nginx/snippets/php-fpm.conf;
448	            fastcgi_param HTTPS on;
449	            fastcgi_read_timeout 120;
450	            fastcgi_send_timeout 120;
451	        }
452	    }
453	
454	    # PHP geral: 60s (suficiente para renderização Elementor normal)
455	    location ~ \.php$ {
456	        try_files \$uri =404;
457	        include /etc/nginx/snippets/php-fpm.conf;
458	        fastcgi_param HTTPS on;
459	        fastcgi_read_timeout 60;
460	        fastcgi_send_timeout 60;
461	    }
462	}
463	SITEEOF
464	
465	# ==============================================================================
466	# ROBOTS.TXT — Proteção contra crawler traps do TEC (apenas prod)
467	# ==============================================================================
468	
469	if [[ "${ENVIRONMENT}" == "prod" ]] && [[ ! -f "${WP_ROOT}/robots.txt" ]]; then
470	    log_info "Criando robots.txt estático em ${WP_ROOT}..."
471	    cat > "${WP_ROOT}/robots.txt" << 'ROBOTSEOF'
472	User-agent: *
473	Allow: /
474	
475	# TEC crawler traps — superfície infinita de URLs
476	Disallow: /eventos/????-??-??/
477	Disallow: /*?tribe-bar-date=
478	Disallow: /*?eventDate=
479	Disallow: /*?eventDisplay=past
480	Disallow: /*?ical=
481	Disallow: /*?outlook-ical=
482	
483	# TEC REST API — custoso, sem uso público
484	Disallow: /wp-json/tribe/events/
485	Disallow: /wp-json/tribe_events/
486	
487	Sitemap: https://FQDN_PLACEHOLDER/sitemap_index.xml
488	ROBOTSEOF
489	    # Substituir placeholder pelo FQDN real (heredoc quoted não expande variáveis)
490	    sed -i "s|FQDN_PLACEHOLDER|${FQDN}|" "${WP_ROOT}/robots.txt"
491	    chown "${WEB_USER}:${WEB_USER}" "${WP_ROOT}/robots.txt"
492	    log_success "robots.txt criado em ${WP_ROOT}/robots.txt"
493	else
494	    if [[ "${ENVIRONMENT}" == "prod" ]]; then
495	        log_info "robots.txt já existe em ${WP_ROOT}/robots.txt — não sobrescreve."
496	    else
497	        log_info "robots.txt não criado (ambiente ${ENVIRONMENT} — dev/hml usam X-Robots-Tag)."
498	    fi
499	fi
500	
501	# ==============================================================================
502	# SERVIDOR DEFAULT - BLOQUEIA ACESSO DIRETO POR IP
503	# ==============================================================================
504	
505	log_info "Configurando drop server para bloquear acesso direto por IP..."
506	
507	# Criar drop server que bloqueia acesso direto por IP
508	# Health check (porta 8080) criado abaixo neste mesmo script.
509	# c1-validate-health.sh apenas testa o endpoint — não cria o arquivo nginx.
510	cat > "/etc/nginx/sites-available/000-default-drop" << 'DROPEOF'
511	# Drop server - bloqueia acesso direto por IP (medida de segurança)
512	server {
513	    listen 80 default_server;
514	    listen [::]:80 default_server;
515	    server_name _;
516	
517	    # Log de tentativas de acesso direto por IP para monitoramento de segurança
518	    access_log /var/log/nginx/blocked-direct-ip.log combined;
519	
520	    # return 444 = Nginx fecha conexão TCP sem enviar resposta HTTP
521	    # Economiza recursos e não revela informações para scanners
522	    return 444;
523	}
524	DROPEOF
525	
526	# ==============================================================================
527	# HEALTH CHECK — Porta 8080 para ALB
528	# ==============================================================================
529	
530	log_info "Criando health check endpoint na porta 8080 para ALB..."
531	
532	cat > "/etc/nginx/sites-available/health-check-8080" << 'HEALTHEOF'
533	# Health check — ALB verifica esta porta (Security Group bloqueia 8080 externamente)
534	server {
535	    listen 8080;
536	    listen [::]:8080;
537	    server_name _;
538	
539	    access_log off;
540	    error_log /dev/null;
541	
542	    location /health {
543	        return 200 "OK\n";
544	        add_header Content-Type text/plain;
545	    }
546	
547	    location /health.txt {
548	        return 200 "OK\n";
549	        add_header Content-Type text/plain;
550	    }
551	
552	    location / {
553	        return 444;
554	    }
555	}
556	HEALTHEOF
557	
558	ln -sf "/etc/nginx/sites-available/health-check-8080" "/etc/nginx/sites-enabled/"
559	log_success "Health check criado: /etc/nginx/sites-available/health-check-8080"
560	
561	# ==============================================================================
562	# ATIVAÇÃO DO SITE
563	# ==============================================================================
564	
565	log_info "Ativando site ${FQDN} com proteção contra acesso direto por IP..."
566	
567	# Enable drop server com prioridade máxima (prefixo 000-)
568	ln -sf "/etc/nginx/sites-available/000-default-drop" "/etc/nginx/sites-enabled/"
569	
570	# Enable site específico do domínio
571	ln -sf "/etc/nginx/sites-available/${FQDN}" "/etc/nginx/sites-enabled/"
572	
573	# Remove antigo default site se existir
574	rm -f /etc/nginx/sites-enabled/default || true
575	
576	# Test configuration and reload
577	log_info "Testando configuração do Nginx..."
578	if nginx -t 2>&1; then
579	    log_success "Configuração nginx válida"
580	    systemctl reload nginx
581	    echo ""
582	    echo "=========================================================================================="
583	    echo "SITE NGINX CONFIGURADO COM SUCESSO!"
584	    echo "=========================================================================================="
585	    echo ""
586	    echo "AMBIENTE ${ENVIRONMENT^^} CONFIGURADO:"
587	    echo "  Domain: ${FQDN}"
588	    echo "  Root: ${WP_ROOT}"
589	    echo "  SSL: Configurado via Load Balancer"
590	    echo "  Real IP: Configurado para ${VPC_CIDR_TRUSTED:-10.0.0.0/8}"
591	    echo "  Drop Server: Acesso direto por IP bloqueado (return 444)"
592	    echo ""
593	    echo "WP ROCKET BYPASS:"
594	    echo "  Nginx serve HTML cacheado do disco sem PHP (~0.015s)"
595	    echo "  Skip: logged-in, POST, query strings → passa para PHP normalmente"
596	    echo ""
597	    echo "HARDENING APLICADO:"
598	    echo "  Rate Limit: wp-login (5r/m, burst=3), xmlrpc (burst=5)"
599	    echo "  wp-cron.php: acesso HTTP externo bloqueado (127.0.0.1 only)"
600	    echo "  Timeouts: php=60s, wp-admin=120s, async-upload=300s"
601	    if [[ "${ENVIRONMENT}" == "prod" ]]; then
602	        echo "  HSTS: max-age=31536000 includeSubDomains (produção)"
603	    else
604	        echo "  HSTS: desabilitado (ambiente não-prod)"
605	    fi
606	    echo ""
607	    echo "CONFIGURAÇÕES DE CACHE:"
608	    echo "  Expires: ${CACHE_EXPIRES}"
609	    echo "  Cache-Control: ${CACHE_CONTROL}"
610	    if [ -n "${ROBOTS_TAG}" ]; then
611	        echo "  Robots: Indexação bloqueada"
612	    else
613	        echo "  Robots: Indexação permitida"
614	    fi
615	    echo ""
616	    echo "PRÓXIMOS PASSOS:"
617	    echo "  1. Execute: sudo ./04b-wordpress-autoconfigure.sh"
618	    echo "  2. Configure plugins: sudo ./06-wp-plugins-themes.sh"
619	    echo "=========================================================================================="
620	else
621	    log_error "Erro na configuração do Nginx. Verifique os arquivos."
622	    exit 1
623	fi
624

