#!/usr/bin/env bash
# ==============================================================================
# Nginx Site Configuration Script - Single Environment with Cache Control
# Autor: Daniel Cambría + Warp
# Versao: 1.8.0
#
# Configura site Nginx com suporte completo a SSL via Load Balancer
# para o ambiente especificado em ENVIRONMENT (prod|hml|dev)
# Usa configurações de cache definidas no ../.env
#
# v1.1.0: Rate limiting, timeouts diferenciados por location, HSTS condicional,
#         bloqueio wp-cron HTTP externo, xmlrpc rate limit (não deny — WPML usa)
# v1.2.0: Criar bloco listen 8080 para ALB health check (/health, /health.txt)
# v1.3.0: Content-Security-Policy em security-headers.conf (Elementor-compatible)
# v1.4.0: Fix MULTISITE via get_env_variable (era ${MULTISITE:-false}, ignorava _PROD/_HML)
# v1.5.0: CSP v3 — GTM, GA, Google Ads, Meta Pixel, RD Station, VLibras, CDN fonts
# v1.6.0: WP Rocket nginx bypass — serve HTML cacheado sem PHP (~0.015s vs ~1-5s)
# v1.7.0: cleaned_args map (strip tracking QS + TEC crawler traps), CF crawler rate limit
# v1.8.0: robots.txt (prod), TEC day-view redirect (multisite), TEC REST API rate limit+timeout
# ==============================================================================
set -euo pipefail

readonly WP_SCRIPT_DESC="Configura sites Nginx"

# Parse argumentos para detectar --help
for arg in "$@"; do
    if [[ "$arg" == "--help" ]] || [[ "$arg" == "-h" ]]; then
        cat <<EOF
================================================================================
Script: 03-nginx-sites.sh
Descrição: Configura sites Nginx
================================================================================

USO:
  $0

COMPORTAMENTO:
  Configura Nginx para servir WordPress com SSL via Load Balancer:
  - Cria snippets de configuração (security headers, PHP-FPM)
  - Detecta versão PHP instalada e configura socket apropriado
  - Configura nginx.conf para SSL via X-Forwarded-Proto
  - Configura Real IP para capturar IP do cliente via Load Balancer
  - Cria configuração de site específica por ambiente (prod/hml/dev)
  - Aplica configurações de cache personalizadas por ambiente
  - Configura drop server (bloqueia acesso direto por IP - segurança)
  - Cria health check endpoint na porta 8080 para Load Balancer
  - Ativa site e recarrega Nginx

VARIÁVEIS DE AMBIENTE (.env):
  ENVIRONMENT                 Ambiente ativo (prod|hml|dev)
  FQDN_{ENV}                 FQDN do site (ex: FQDN_PROD)
  WP_ROOT_{ENV}              Diretório raiz do WordPress
  CACHE_CONTROL_{ENV}        Diretivas Cache-Control para arquivos estáticos
  CACHE_EXPIRES_{ENV}        Tempo de expiração do cache
  ROBOTS_TAG_{ENV}           Tag robots para ambientes não-prod
  VPC_CIDR_TRUSTED           CIDR da VPC para Real IP (padrão: 10.0.0.0/8)

NOTAS:
  - SSL terminado no Load Balancer, não no servidor
  - Acesso direto por IP bloqueado (return 444)
  - Health check na porta 8080 gerenciado por arquivo dedicado (não por este script)
  - Configurações de cache controladas por ambiente

================================================================================
EOF
        exit 0
    fi
done

# Carregar helpers usando a abordagem padronizada
source "$(dirname "$0")/../helpers/load-helpers.sh"
load_helper "common.sh"
load_helper "config-helper.sh"

log_info "Configurando site Nginx para ambiente: ${ENVIRONMENT}"

# ==============================================================================
# SNIPPETS COMUNS
# ==============================================================================

log_info "Criando snippets de configuração..."

# Security headers
cat > /etc/nginx/snippets/security-headers.conf << 'SECEOF'
add_header X-Frame-Options "SAMEORIGIN" always;
add_header X-Content-Type-Options "nosniff" always;
add_header Referrer-Policy "strict-origin-when-cross-origin" always;
add_header Permissions-Policy "interest-cohort=()" always;
# CSP: unsafe-inline/eval necessários para Elementor + JetEngine + WPML
# data: em script-src necessário para WP Rocket Delay JS (execução via data: URIs)
# Domínios: GTM, GA, Google Ads, Meta Pixel, RD Station, VLibras, reCAPTCHA, Google Charts
# frame-ancestors substitui X-Frame-Options em browsers modernos
add_header Content-Security-Policy "default-src 'self'; script-src 'self' 'unsafe-inline' 'unsafe-eval' https://www.googletagmanager.com https://www.google-analytics.com https://www.google.com https://www.gstatic.com https://googleads.g.doubleclick.net https://connect.facebook.net https://d335luupugsy2.cloudfront.net https://d1sag09wwfbul8.cloudfront.net https://vlibras.gov.br https://cdn.jsdelivr.net blob: data:; style-src 'self' 'unsafe-inline' https://fonts.googleapis.com https://fonts.cdnfonts.com; img-src 'self' data: https:; font-src 'self' data: https://fonts.gstatic.com https://fonts.cdnfonts.com; frame-src 'self' https://www.google.com https://vlibras.gov.br https://www.facebook.com; frame-ancestors 'self'; connect-src 'self' https://www.google-analytics.com https://analytics.google.com https://www.googletagmanager.com https://stats.g.doubleclick.net https://www.google.com https://connect.facebook.net https://vlibras.gov.br https://popups.rdstation.com.br https://d335luupugsy2.cloudfront.net; worker-src 'self' blob:; media-src 'self' https://s3.us-east-1.amazonaws.com; object-src 'none';" always;
SECEOF

# PHP-FPM configuration - detecta versão PHP automaticamente
log_info "Detectando versão PHP instalada..."

# Detectar versão PHP instalada
if [[ -S "/run/php/php8.3-fpm-wordpress.sock" ]]; then
    PHP_SOCKET="/run/php/php8.3-fpm-wordpress.sock"
    log_success "Usando socket PHP 8.3 customizado"
elif [[ -S "/run/php/php8.2-fpm-wordpress.sock" ]]; then
    PHP_SOCKET="/run/php/php8.2-fpm-wordpress.sock"
    log_success "Usando socket PHP 8.2 customizado"
elif [[ -S "/run/php/php8.1-fpm-wordpress.sock" ]]; then
    PHP_SOCKET="/run/php/php8.1-fpm-wordpress.sock"
    log_success "Usando socket PHP 8.1 customizado"
elif [[ -S "/run/php/php8.3-fpm.sock" ]]; then
    PHP_SOCKET="/run/php/php8.3-fpm.sock"
    log_success "Usando socket PHP 8.3 padrão"
elif [[ -S "/run/php/php8.2-fpm.sock" ]]; then
    PHP_SOCKET="/run/php/php8.2-fpm.sock"
    log_success "Usando socket PHP 8.2 padrão"
elif [[ -S "/run/php/php8.1-fpm.sock" ]]; then
    PHP_SOCKET="/run/php/php8.1-fpm.sock"
    log_success "Usando socket PHP 8.1 padrão"
else
    log_error "Nenhum socket PHP-FPM encontrado!"
    log_info "Sockets disponíveis em /run/php/:"
    ls -la /run/php/ || echo "Diretório /run/php/ não encontrado"
    exit 1
fi

log_info "Socket PHP selecionado: $PHP_SOCKET"

cat > /etc/nginx/snippets/php-fpm.conf << PHPEOF
include fastcgi_params;
fastcgi_pass unix:$PHP_SOCKET;
fastcgi_param SCRIPT_FILENAME \$realpath_root\$fastcgi_script_name;
fastcgi_param HTTPS on;
fastcgi_connect_timeout 10;
PHPEOF
# Nota: fastcgi_read_timeout e fastcgi_send_timeout são definidos por location
# no server block (60s geral, 120s wp-admin, 300s async-upload) — não aqui.

# ==============================================================================
# CONFIGURAÇÃO NGINX PRINCIPAL - SSL E REAL IP
# ==============================================================================

log_info "Configurando nginx.conf para SSL e Real IP..."

# Backup do nginx.conf original
cp /etc/nginx/nginx.conf /etc/nginx/nginx.conf.bak 2>/dev/null || true

log_info "Verificando configurações de SSL e Real IP no nginx.conf..."

# Configurar Real IP (para que nginx veja o IP real do visitante via X-Forwarded-For do ALB)
# Nota: o map $http_x_forwarded_proto → $fastcgi_https foi removido — fastcgi_param HTTPS on
# é definido estaticamente no snippet php-fpm.conf (EC2 sempre atrás de ALB com SSL offloading)
if ! grep -q "real_ip_header X-Forwarded-For" /etc/nginx/nginx.conf; then
    log_info "Configuração de Real IP não encontrada. Adicionando..."

    # Usar VPC_CIDR_TRUSTED do .env (fallback: 10.0.0.0/8 cobre a maioria das VPCs AWS)
    VPC_CIDR="${VPC_CIDR_TRUSTED:-10.0.0.0/8}"

    # Criar arquivo temporário com as configurações
    cat > /tmp/nginx_realip_config.tmp << RIPEOF

    # ==== Real IP Configuration (ALB → EC2) ====
    real_ip_header X-Forwarded-For;
    real_ip_recursive on;
    set_real_ip_from ${VPC_CIDR};
RIPEOF

    # Inserir as configurações após a linha 'http {'
    sed -i '/^http {$/r /tmp/nginx_realip_config.tmp' /etc/nginx/nginx.conf

    # Remover arquivo temporário
    rm -f /tmp/nginx_realip_config.tmp
    log_success "Configuração de Real IP adicionada."
else
    log_info "Configuração de Real IP já existe. Nenhuma alteração necessária."
fi

# Rate limiting zone: wp-login brute force (idempotente)
if ! grep -q "zone=wp_login" /etc/nginx/nginx.conf; then
    log_info "Adicionando rate limiting zone wp_login ao nginx.conf..."
    cat > /tmp/nginx_ratelimit.tmp << 'RLEOF'

    # ==== Rate Limiting: wp-login brute force ====
    # $binary_remote_addr usa o IP real do cliente (ngx_http_realip_module já processou X-Forwarded-For)
    limit_req_zone $binary_remote_addr zone=wp_login:10m rate=5r/m;

    # ==== Rate Limiting: CloudFront crawlers ====
    map $http_user_agent $is_cf_crawler {
        default             0;
        "Amazon CloudFront" 1;
        ""                  1;
    }

    map $is_cf_crawler $cf_crawler_key {
        0   "";
        1   $binary_remote_addr;
    }

    limit_req_zone $cf_crawler_key zone=cf_crawlers:10m rate=2r/s;
RLEOF
    sed -i '/^http {$/r /tmp/nginx_ratelimit.tmp' /etc/nginx/nginx.conf
    rm -f /tmp/nginx_ratelimit.tmp
    log_success "Rate limiting zones adicionadas."
else
    log_info "Rate limiting zones já existem. Nenhuma alteração necessária."
fi

# ==============================================================================
# WP ROCKET NGINX BYPASS — serve HTML cacheado sem PHP
# ==============================================================================

# Maps no bloco http {} para detectar cookies/method e resolver path do cache.
# WP Rocket grava HTML em wp-content/cache/wp-rocket/$host/$uri/index-https.html.
# Nginx serve direto do disco (~0.015s) se: não logado, GET, sem query string.
if ! grep -q "rocket_is_logged_in" /etc/nginx/nginx.conf; then
    log_info "Adicionando WP Rocket bypass maps ao nginx.conf..."
    cat > /tmp/nginx_rocket_maps.tmp << 'ROCKETEOF'

    # ==== WP Rocket Nginx Bypass ====
    # Detecta cookies de login/postpass/comment para pular cache
    map $http_cookie $rocket_is_logged_in {
        default 0;
        "~*wordpress_logged_in_" 1;
        "~*wp-postpass_" 1;
        "~*comment_author_" 1;
    }

    # Clean args: strip tracking QS e crawler traps do TEC (servir cache)
    # Se $args contém qualquer destes, mapeamos para "" (= sem QS = cache hit)
    map $args $cleaned_args {
        default          $args;
        ""               "";
        "~*gclid="       "";
        "~*gad_source="  "";
        "~*gbraid="      "";
        "~*gclsrc="      "";
        "~*utm_"         "";
        "~*fbclid="      "";
        "~*msclkid="     "";
        "~*_ga="         "";
        "~*_gl="         "";
        "~*ical="        "";
        "~*outlook-ical=" "";
        "~*nowprocket="  "";
        "~*eventDisplay=past" "";
        "~*tribe-bar-date=" "";
        "~*eventDate="   "";
    }

    # Motivo para pular cache: logado, POST, ou query string funcional presente
    map "$rocket_is_logged_in:$request_method:$cleaned_args" $rocket_skip_reason {
        default "";
        "~^1:" "logged_in";
        "~^.:POST" "post_request";
        "~^.:GET:.+" "query_string";
    }

    # Path do cache para URIs com trailing slash (maioria das páginas)
    map $rocket_skip_reason $rocket_cache_file {
        default "/wp-content/cache/wp-rocket/$http_host/$uri/index-https.html";
        "~.+" "";
    }

    # Path do cache para a raiz (/) — sem trailing slash duplicada
    map "$rocket_skip_reason:$uri" $rocket_root_cache {
        default "";
        ":/" "/wp-content/cache/wp-rocket/$http_host/index-https.html";
    }
ROCKETEOF
    sed -i '/^http {$/r /tmp/nginx_rocket_maps.tmp' /etc/nginx/nginx.conf
    rm -f /tmp/nginx_rocket_maps.tmp
    log_success "WP Rocket bypass maps adicionados ao nginx.conf."
else
    log_info "WP Rocket bypass maps já existem no nginx.conf. Nenhuma alteração necessária."
fi

# ==============================================================================
# CONFIGURAÇÃO DO SITE BASEADO NO AMBIENTE
# ==============================================================================

# Validar ambiente
if [[ ! "${ENVIRONMENT}" =~ ^(prod|hml|dev)$ ]]; then
    log_error "ENVIRONMENT deve ser: prod, hml ou dev. Atual: ${ENVIRONMENT}"
    exit 1
fi

log_info "Carregando configurações de cache para ambiente ${ENVIRONMENT}..."

# Usar get_env_variable para resolver variáveis específicas do ambiente
FQDN=$(get_env_variable "FQDN" || echo "")
WP_ROOT=$(get_env_variable "WP_ROOT" || echo "")
CACHE_CONTROL=$(get_env_variable "CACHE_CONTROL" || echo "public, max-age=31536000, immutable")
CACHE_EXPIRES=$(get_env_variable "CACHE_EXPIRES" || echo "1y")
ROBOTS_TAG=$(get_env_variable "ROBOTS_TAG" || echo "")

# Validar variáveis obrigatórias
if [[ -z "$FQDN" ]]; then
    log_error "FQDN não configurado para ambiente ${ENVIRONMENT}"
    log_error "Configure FQDN_${ENVIRONMENT^^} no arquivo ../.env"
    exit 1
fi

if [[ -z "$WP_ROOT" ]]; then
    log_error "WP_ROOT não configurado para ambiente ${ENVIRONMENT}"
    log_error "Configure WP_ROOT_${ENVIRONMENT^^} no arquivo ../.env"
    exit 1
fi

log_info "Configurações carregadas:"
log_info "  - Cache Expires: ${CACHE_EXPIRES}"
log_info "  - Cache Control: ${CACHE_CONTROL}"
log_info "  - Robots Tag: $([ -n "${ROBOTS_TAG}" ] && echo "Configurado" || echo "Desabilitado")"

log_info "Configurando site para ambiente ${ENVIRONMENT}..."

# HSTS: apenas em produção (evita HSTS permanente em ambientes não-prod que podem mudar de URL)
HSTS_HEADER=""
if [[ "${ENVIRONMENT}" == "prod" ]]; then
    HSTS_HEADER='add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;'
fi

# Gerar bloco de rewrites para multisite subdirectory (se MULTISITE=true)
MULTISITE_REWRITES=""
STATIC_TRY_FILES="=404"
MULTISITE=$(get_env_variable "MULTISITE" || echo "false")
if [[ "${MULTISITE}" == "true" ]]; then
    log_info "Multisite ativado: adicionando rewrite rules de subdirectory ao nginx..."
    MULTISITE_REWRITES=$(cat << 'MSEOF'

    # WordPress Multisite subdirectory rewrites
    if (!-e $request_filename) {
        rewrite /wp-admin$ $scheme://$host$uri/ permanent;
        rewrite ^(/[^/]+)?(/wp-.*) $2 last;
        rewrite ^(/[^/]+)?(/.*\.php) $2 last;
    }
MSEOF
)
    # Multisite: static files de subsites nao existem no filesystem, precisam do PHP
    STATIC_TRY_FILES="/index.php?\$args"
fi

cat > "/etc/nginx/sites-available/${FQDN}" << SITEEOF
server {
    listen 80;
    server_name ${FQDN};
    root ${WP_ROOT};
    index index.php index.html;
    include /etc/nginx/snippets/security-headers.conf;

    ${ROBOTS_TAG}
    ${HSTS_HEADER}
    client_max_body_size 128M;

    # WordPress permalinks + WP Rocket bypass
    # Ordem: arquivo exato → cache raiz → cache página → diretório → PHP
    location / {
        limit_req zone=cf_crawlers burst=5 nodelay;
        try_files \$uri \$rocket_root_cache \$rocket_cache_file \$uri/ /index.php?\$args;
    }
${MULTISITE_REWRITES}
    # Static files caching - Configurações controladas por variáveis
    location ~* \.(?:js|css|png|jpg|jpeg|gif|svg|woff2?|ttf|eot)$ {
        expires ${CACHE_EXPIRES};
        add_header Cache-Control "${CACHE_CONTROL}";
        try_files \$uri ${STATIC_TRY_FILES};
    }

    # Bloquear indexacao de PDFs pelo Google
    location ~* \.pdf$ {
        add_header X-Robots-Tag "noindex, nofollow" always;
        try_files \$uri =404;
    }

    # TEC day-view: redirect crawlers para /eventos/ (colapsa superfície infinita de datas)
    # Multisite: (/[^/]+)? captura prefixo de subsite como /cultura/
    location ~ "^(/[^/]+)?/eventos/\\d{4}-\\d{2}-\\d{2}" {
        limit_req zone=cf_crawlers burst=2 nodelay;
        if (\$rocket_is_logged_in = 0) {
            return 301 \$1/eventos/;
        }
        try_files \$uri \$uri/ /index.php?\$args;
    }

    # TEC REST API: rate limit + timeout curto (sem uso público)
    # Usa rewrite+break (não try_files) para que fastcgi_read_timeout 15 se aplique aqui
    location ~ ^/wp-json/tribe {
        limit_req zone=cf_crawlers burst=2 nodelay;
        rewrite ^ /index.php?\$args break;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 15;
        fastcgi_send_timeout 15;
    }

    # Security restrictions
    location ~ /\.ht { deny all; }
    location ~* /(?:wp-config\.php|readme\.html|license\.txt)$ { deny all; }

    # ==== Hardening: rate limiting e bloqueios ====

    # wp-login.php: rate limit anti-brute-force (5 req/min, burst=3)
    location = /wp-login.php {
        limit_req zone=wp_login burst=3 nodelay;
        try_files \$uri =404;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 60;
        fastcgi_send_timeout 60;
    }

    # xmlrpc.php: rate limit moderado — NÃO bloquear (WPML usa para sync multilíngue)
    # burst=5 permite sync de múltiplos posts sem throttling; impede abuso em massa
    location = /xmlrpc.php {
        limit_req zone=wp_login burst=5 nodelay;
        try_files \$uri =404;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 60;
        fastcgi_send_timeout 60;
    }

    # wp-cron.php: bloquear acesso HTTP externo (cron roda via sistema PHP direto)
    # O rewrite multisite (flag last) garante que /subsite/wp-cron.php também é bloqueado
    location = /wp-cron.php {
        allow 127.0.0.1;
        deny all;
        try_files \$uri =404;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 60;
        fastcgi_send_timeout 60;
    }

    # wp-admin/async-upload.php: upload de arquivos grandes (PDFs, imagens)
    location = /wp-admin/async-upload.php {
        try_files \$uri =404;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 300;
        fastcgi_send_timeout 300;
        client_max_body_size 128M;
    }

    # wp-admin: operações longas (exports, imports, atualizações)
    location ~ ^/wp-admin/ {
        try_files \$uri \$uri/ /index.php?\$args;
        location ~ \.php$ {
            try_files \$uri =404;
            include /etc/nginx/snippets/php-fpm.conf;
            fastcgi_param HTTPS on;
            fastcgi_read_timeout 120;
            fastcgi_send_timeout 120;
        }
    }

    # PHP geral: 60s (suficiente para renderização Elementor normal)
    location ~ \.php$ {
        try_files \$uri =404;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 60;
        fastcgi_send_timeout 60;
    }
}
SITEEOF

# ==============================================================================
# ROBOTS.TXT — Proteção contra crawler traps do TEC (apenas prod)
# ==============================================================================

if [[ "${ENVIRONMENT}" == "prod" ]] && [[ ! -f "${WP_ROOT}/robots.txt" ]]; then
    log_info "Criando robots.txt estático em ${WP_ROOT}..."
    cat > "${WP_ROOT}/robots.txt" << 'ROBOTSEOF'
User-agent: *
Allow: /

# TEC crawler traps — superfície infinita de URLs
Disallow: /eventos/????-??-??/
Disallow: /*?tribe-bar-date=
Disallow: /*?eventDate=
Disallow: /*?eventDisplay=past
Disallow: /*?ical=
Disallow: /*?outlook-ical=

# TEC REST API — custoso, sem uso público
Disallow: /wp-json/tribe/events/
Disallow: /wp-json/tribe_events/

Sitemap: https://FQDN_PLACEHOLDER/sitemap_index.xml
ROBOTSEOF
    # Substituir placeholder pelo FQDN real (heredoc quoted não expande variáveis)
    sed -i "s|FQDN_PLACEHOLDER|${FQDN}|" "${WP_ROOT}/robots.txt"
    chown "${WEB_USER}:${WEB_USER}" "${WP_ROOT}/robots.txt"
    log_success "robots.txt criado em ${WP_ROOT}/robots.txt"
else
    if [[ "${ENVIRONMENT}" == "prod" ]]; then
        log_info "robots.txt já existe em ${WP_ROOT}/robots.txt — não sobrescreve."
    else
        log_info "robots.txt não criado (ambiente ${ENVIRONMENT} — dev/hml usam X-Robots-Tag)."
    fi
fi

# ==============================================================================
# SERVIDOR DEFAULT - BLOQUEIA ACESSO DIRETO POR IP
# ==============================================================================

log_info "Configurando drop server para bloquear acesso direto por IP..."

# Criar drop server que bloqueia acesso direto por IP
# Health check (porta 8080) criado abaixo neste mesmo script.
# c1-validate-health.sh apenas testa o endpoint — não cria o arquivo nginx.
cat > "/etc/nginx/sites-available/000-default-drop" << 'DROPEOF'
# Drop server - bloqueia acesso direto por IP (medida de segurança)
server {
    listen 80 default_server;
    listen [::]:80 default_server;
    server_name _;

    # Log de tentativas de acesso direto por IP para monitoramento de segurança
    access_log /var/log/nginx/blocked-direct-ip.log combined;

    # return 444 = Nginx fecha conexão TCP sem enviar resposta HTTP
    # Economiza recursos e não revela informações para scanners
    return 444;
}
DROPEOF

# ==============================================================================
# HEALTH CHECK — Porta 8080 para ALB
# ==============================================================================

log_info "Criando health check endpoint na porta 8080 para ALB..."

cat > "/etc/nginx/sites-available/health-check-8080" << 'HEALTHEOF'
# Health check — ALB verifica esta porta (Security Group bloqueia 8080 externamente)
server {
    listen 8080;
    listen [::]:8080;
    server_name _;

    access_log off;
    error_log /dev/null;

    location /health {
        return 200 "OK\n";
        add_header Content-Type text/plain;
    }

    location /health.txt {
        return 200 "OK\n";
        add_header Content-Type text/plain;
    }

    location / {
        return 444;
    }
}
HEALTHEOF

ln -sf "/etc/nginx/sites-available/health-check-8080" "/etc/nginx/sites-enabled/"
log_success "Health check criado: /etc/nginx/sites-available/health-check-8080"

# ==============================================================================
# ATIVAÇÃO DO SITE
# ==============================================================================

log_info "Ativando site ${FQDN} com proteção contra acesso direto por IP..."

# Enable drop server com prioridade máxima (prefixo 000-)
ln -sf "/etc/nginx/sites-available/000-default-drop" "/etc/nginx/sites-enabled/"

# Enable site específico do domínio
ln -sf "/etc/nginx/sites-available/${FQDN}" "/etc/nginx/sites-enabled/"

# Remove antigo default site se existir
rm -f /etc/nginx/sites-enabled/default || true

# Test configuration and reload
log_info "Testando configuração do Nginx..."
if nginx -t 2>&1; then
    log_success "Configuração nginx válida"
    systemctl reload nginx
    echo ""
    echo "=========================================================================================="
    echo "SITE NGINX CONFIGURADO COM SUCESSO!"
    echo "=========================================================================================="
    echo ""
    echo "AMBIENTE ${ENVIRONMENT^^} CONFIGURADO:"
    echo "  Domain: ${FQDN}"
    echo "  Root: ${WP_ROOT}"
    echo "  SSL: Configurado via Load Balancer"
    echo "  Real IP: Configurado para ${VPC_CIDR_TRUSTED:-10.0.0.0/8}"
    echo "  Drop Server: Acesso direto por IP bloqueado (return 444)"
    echo ""
    echo "WP ROCKET BYPASS:"
    echo "  Nginx serve HTML cacheado do disco sem PHP (~0.015s)"
    echo "  Skip: logged-in, POST, query strings → passa para PHP normalmente"
    echo ""
    echo "HARDENING APLICADO:"
    echo "  Rate Limit: wp-login (5r/m, burst=3), xmlrpc (burst=5)"
    echo "  wp-cron.php: acesso HTTP externo bloqueado (127.0.0.1 only)"
    echo "  Timeouts: php=60s, wp-admin=120s, async-upload=300s"
    if [[ "${ENVIRONMENT}" == "prod" ]]; then
        echo "  HSTS: max-age=31536000 includeSubDomains (produção)"
    else
        echo "  HSTS: desabilitado (ambiente não-prod)"
    fi
    echo ""
    echo "CONFIGURAÇÕES DE CACHE:"
    echo "  Expires: ${CACHE_EXPIRES}"
    echo "  Cache-Control: ${CACHE_CONTROL}"
    if [ -n "${ROBOTS_TAG}" ]; then
        echo "  Robots: Indexação bloqueada"
    else
        echo "  Robots: Indexação permitida"
    fi
    echo ""
    echo "PRÓXIMOS PASSOS:"
    echo "  1. Execute: sudo ./04b-wordpress-autoconfigure.sh"
    echo "  2. Configure plugins: sudo ./06-wp-plugins-themes.sh"
    echo "=========================================================================================="
else
    log_error "Erro na configuração do Nginx. Verifique os arquivos."
    exit 1
fi
